// Valida completitud + normaliza + calcula score BANT+ 0-100.
// Framework: /n8n-workflows/scoring-spec.md
//
// Reglas de completitud:
//   - nombre no vacio
//   - whatsapp O email
//   - al menos 3 de 4 entre: plazo, rango_presupuesto, forma_pago, uso
// Si falta algo -> retorna { ok: false, reason: 'faltan_datos', faltantes: [...] }

const d = $json;

if (!d.session_id || typeof d.session_id !== 'string') {
  throw new Error('session_id requerido');
}
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!UUID_RE.test(d.session_id)) {
  throw new Error('session_id debe ser UUID valido');
}

// --- Normalizacion ---
const PLAZO_MAP = {
  'inmediato': 'ahora',
  'ahora': 'ahora',
  '1-3m': '1_a_3_meses',
  '1_a_3_meses': '1_a_3_meses',
  '3-6m': '3_a_6_meses',
  '3_a_6_meses': '3_a_6_meses',
  '6-12m': '6_a_12_meses',
  '6_a_12_meses': '6_a_12_meses',
  '12m+': 'mas_de_1_ano',
  'mas_de_1_ano': 'mas_de_1_ano',
  'no_definido': 'no_definido',
};
const INTENCION_TO_USO = {
  'inversion': 'inversion',
  'segunda_vivienda': 'segunda',
  'vivir_permanente': 'vivienda',
  'evaluando': 'no_definido',
  'no_definido': 'no_definido',
};
const USO_ENUM = new Set(['vivienda', 'segunda', 'inversion', 'no_definido']);
const FORMA_PAGO_ENUM = new Set(['contado', 'credito', 'subsidio', 'mixto', 'no_definido']);
const RANGO_ENUM = new Set(['<20M', '20-40M', '40-60M', '>60M', 'no_definido']);
const DECISOR_ENUM = new Set(['solo', 'pareja', 'familia', 'no_definido']);

const nombre = [d.nombre, d.apellido].filter(Boolean).join(' ').trim().slice(0, 150);
const whatsapp = d.whatsapp ? String(d.whatsapp).slice(0, 30) : null;
const email = d.email ? String(d.email).slice(0, 120) : null;
const plazo = PLAZO_MAP[d.plazo] || 'no_definido';
let uso = (d.uso && USO_ENUM.has(d.uso)) ? d.uso : null;
if (!uso && d.intencion) uso = INTENCION_TO_USO[d.intencion] || 'no_definido';
if (!uso) uso = 'no_definido';
const forma_pago = (d.forma_pago && FORMA_PAGO_ENUM.has(d.forma_pago)) ? d.forma_pago : 'no_definido';
const pre_aprobacion = typeof d.pre_aprobacion === 'boolean' ? d.pre_aprobacion : null;
const decisor = (d.decisor && DECISOR_ENUM.has(d.decisor)) ? d.decisor : 'no_definido';
const rango_presupuesto = (d.rango_presupuesto && RANGO_ENUM.has(d.rango_presupuesto)) ? d.rango_presupuesto : 'no_definido';
const resumen = (d.resumen || d.resumen_conversacion || '').toString().slice(0, 800);

// --- Validacion de completitud ---
const faltantes = [];
if (!nombre) faltantes.push('nombre');
if (!whatsapp && !email) faltantes.push('whatsapp_o_email');

const senalesDefinidas = [
  plazo !== 'no_definido',
  rango_presupuesto !== 'no_definido',
  forma_pago !== 'no_definido',
  uso !== 'no_definido',
].filter(Boolean).length;

if (senalesDefinidas < 3) {
  const senalesFaltantes = [];
  if (plazo === 'no_definido') senalesFaltantes.push('plazo');
  if (rango_presupuesto === 'no_definido') senalesFaltantes.push('rango_presupuesto');
  if (forma_pago === 'no_definido') senalesFaltantes.push('forma_pago');
  if (uso === 'no_definido') senalesFaltantes.push('uso');
  faltantes.push(`minimo_3_de_4_senales (faltan: ${senalesFaltantes.join(',')})`);
}

if (faltantes.length > 0) {
  return [{ json: {
    ok: false,
    reason: 'faltan_datos',
    faltantes,
    session_id: d.session_id,
    tool_output_text: null,
  } }];
}

// --- Scoring BANT+ 0-100 ---
const weights = {};

// plazo (25)
const plazoPts = {
  'ahora': 25,
  '1_a_3_meses': 22,
  '3_a_6_meses': 15,
  '6_a_12_meses': 8,
  'mas_de_1_ano': 3,
  'no_definido': 0,
};
weights.plazo = plazoPts[plazo] || 0;

// rango_presupuesto (25)
const rangoPts = {
  '>60M': 25,
  '40-60M': 22,
  '20-40M': 18,
  '<20M': 10,
  'no_definido': 0,
};
weights.rango_presupuesto = rangoPts[rango_presupuesto] || 0;

// forma_pago (15)
if (forma_pago === 'contado') weights.forma_pago = 15;
else if (forma_pago === 'credito' && pre_aprobacion === true) weights.forma_pago = 14;
else if (forma_pago === 'credito') weights.forma_pago = 10;
else if (forma_pago === 'mixto') weights.forma_pago = 10;
else if (forma_pago === 'subsidio') weights.forma_pago = 6;
else weights.forma_pago = 0;

// uso (15)
const usoPts = { 'inversion': 15, 'segunda': 13, 'vivienda': 10, 'no_definido': 0 };
weights.uso = usoPts[uso] || 0;

// decisor (10)
const decisorPts = { 'solo': 10, 'pareja': 8, 'familia': 5, 'no_definido': 0 };
weights.decisor = decisorPts[decisor] || 0;

// contacto (10)
if (whatsapp && email) weights.contacto = 10;
else if (whatsapp || email) weights.contacto = 7;
else if (nombre) weights.contacto = 3;
else weights.contacto = 0;

let scoreNumeric = Object.values(weights).reduce((a, b) => a + b, 0);
if (d.override_caliente === true) {
  scoreNumeric = Math.max(scoreNumeric, 75);
}
scoreNumeric = Math.min(100, Math.max(0, scoreNumeric));

const scoreLabel = scoreNumeric >= 70 ? 'CALIENTE' : scoreNumeric >= 40 ? 'TIBIO' : 'FRIO';

return [{ json: {
  ok: true,
  session_id: d.session_id,
  nombre,
  whatsapp,
  email,
  plazo,
  uso,
  forma_pago,
  pre_aprobacion,
  decisor,
  rango_presupuesto,
  intencion: d.intencion || (uso === 'segunda' ? 'segunda_vivienda' : uso === 'vivienda' ? 'vivir_permanente' : uso === 'inversion' ? 'inversion' : 'no_definido'),
  resumen,
  score_numeric: scoreNumeric,
  score: scoreLabel,
  weights,
  override_caliente: !!d.override_caliente,
} }];

// Construye body del upsert con score_history actualizado.

const scored = $('Compute Score').first().json;
const current = $json;

let history = [];
if (Array.isArray(current) && current.length > 0) {
  history = Array.isArray(current[0].score_history) ? current[0].score_history : [];
} else if (current && current.score_history) {
  history = Array.isArray(current.score_history) ? current.score_history : [];
}

const newEntry = {
  at: new Date().toISOString(),
  action: 'final_score',
  score_numeric: scored.score_numeric,
  score_label: scored.score,
  override_caliente: scored.override_caliente,
  weights_applied: scored.weights,
};

const body = {
  session_id: scored.session_id,
  nombre: scored.nombre,
  whatsapp: scored.whatsapp,
  email: scored.email,
  plazo: scored.plazo,
  uso: scored.uso,
  forma_pago: scored.forma_pago,
  pre_aprobacion: scored.pre_aprobacion,
  decisor: scored.decisor,
  rango_presupuesto: scored.rango_presupuesto,
  intencion: scored.intencion,
  presupuesto: scored.forma_pago, // legacy compat
  resumen: scored.resumen,
  score: scored.score,
  score_numeric: scored.score_numeric,
  score_history: [...history, newEntry],
};

return [{ json: body }];

const scored = $('Compute Score').first().json;
const upsertResponse = $json;
let lead_id = null;
if (Array.isArray(upsertResponse) && upsertResponse.length > 0) {
  lead_id = upsertResponse[0].id;
} else if (upsertResponse && upsertResponse.id) {
  lead_id = upsertResponse.id;
}

const primerNombre = (scored.nombre || '').split(' ')[0] || 'hola';

let tool_output_text;
if (scored.score === 'CALIENTE') {
  tool_output_text = `Listo, ${primerNombre}. Ya guarde tu informacion completa. Un asesor del equipo te va a contactar por WhatsApp en las proximas horas (lun-vie 9-19). Si quieres adelantarte, podes escribirles directamente al +56 9 4032 9987.`;
} else if (scored.score === 'TIBIO') {
  tool_output_text = `Genial, ${primerNombre}. Deje tu informacion registrada. Si aun no tenes el brochure te lo puedo enviar ahora mismo por WhatsApp o correo. Y cuando quieras avanzar, me avisas y paso tu caso al equipo.`;
} else {
  tool_output_text = `Gracias ${primerNombre}. Dejo tu info registrada. Cuando estes mas cerca de decidir, vuelves cuando quieras — aqui sigue abierto el canal.`;
}

return [{ json: {
  ok: true,
  lead_id,
  score: scored.score,
  score_numeric: scored.score_numeric,
  session_id: scored.session_id,
  tool_output_text,
} }];

// Rama de datos incompletos: devuelve al agente lo que falta.
const v = $json;
return [{ json: {
  ok: false,
  reason: v.reason,
  faltantes: v.faltantes,
  session_id: v.session_id,
  tool_output_text: null,
} }];
